"""COCO (Common Objects in Context) format normalizer.

Supports all three COCO annotation types:
- **instances** — object detection (bboxes, masks, categories)
- **stuff** — stuff segmentation (sky, grass, road, etc.)
- **keypoints** — person pose keypoints

Columns produced per image:

========================  ==============  ================================================
Column                    Type            Content
========================  ==============  ================================================
images                    IMAGE           Source image file bytes
mask                      SEGMENT_MASK    Instance segmentation mask PNG (category per pixel)
boxes                     JSONB           Array of [x,y,w,h] bounding boxes
categories                JSONB           Array of category indices per annotation
super_categories          JSONB           Array of super-category indices per annotation
annotations               JSONB           Array of annotation dicts (bbox, category_id, area)
areas                     JSONB           Array of area values per annotation
iscrowds                  JSONB           Array of is-crowd flags per annotation
num_objects               INT64           Number of instance annotations
images_meta               JSONB           COCO image metadata dict
captions                  JSONB           List of caption strings
========================  ==============  ================================================

Stuff columns (when stuff annotations are available):

========================  ==============  ================================================
stuff/mask                SEGMENT_MASK    Stuff segmentation mask PNG (category per pixel)
stuff/boxes               BOUNDING_BOX    Array of [x,y,w,h] bounding boxes
stuff/categories          JSONB           Array of stuff category indices per annotation
stuff/super_categories    JSONB           Array of stuff super-category indices
stuff/areas               JSONB           Array of area values per annotation
stuff/iscrowds            JSONB           Array of is-crowd flags per annotation
========================  ==============  ================================================

Pose columns (when keypoint annotations are available):

========================  ==============  ================================================
pose/keypoints            JSONB           Array of keypoint arrays (51 values each)
pose/boxes                BOUNDING_BOX    Array of [x,y,w,h] bounding boxes
pose/categories           JSONB           Array of pose category indices
pose/super_categories     JSONB           Array of pose super-category indices
========================  ==============  ================================================

Requires ``pycocotools``, ``Pillow``, and ``numpy``.
"""

from __future__ import annotations

import io
import json as _json
import logging
from pathlib import Path
from typing import Iterator, Dict, List, Any, Optional, Union

from .base import Format

logger = logging.getLogger(__name__)


class Coco(Format):
    """Format object for standard COCO datasets.

    Automatically detects available annotation files (instances, stuff,
    keypoints, captions) from the annotations directory.

    Args:
        images_dir: Directory containing images.
        annotations_dir: Directory containing annotation JSON files.
        instances_json: Explicit path to instances JSON.
        stuff_json: Explicit path to stuff JSON. Set to ``False`` to skip.
        keypoints_json: Explicit path to keypoints JSON. Set to ``False`` to skip.
        captions_json: Explicit path to captions JSON. Set to ``False`` to skip.
        batch_size: Number of images per yielded batch (default 100).
        max_images: Maximum number of images to ingest.
    """

    def __init__(
        self,
        images_dir: Union[str, Path],
        annotations_dir: Optional[Union[str, Path]] = None,
        *,
        instances_json: Optional[Union[str, Path]] = None,
        stuff_json: Optional[Union[str, Path, bool]] = None,
        keypoints_json: Optional[Union[str, Path, bool]] = None,
        captions_json: Optional[Union[str, Path, bool]] = None,
        batch_size: int = 100,
        max_images: Optional[int] = None,
    ):
        self.images_dir = Path(images_dir)
        self.batch_size = batch_size
        self.max_images = max_images

        self._split = self.images_dir.name

        if annotations_dir is not None:
            self._ann_dir = Path(annotations_dir)
        else:
            self._ann_dir = self.images_dir.parent / "annotations"

        # Instances (required)
        if instances_json is not None:
            self._instances_json = Path(instances_json)
        else:
            self._instances_json = self._ann_dir / f"instances_{self._split}.json"

        # Stuff (auto-detect)
        self._stuff_json = self._resolve_optional_ann(stuff_json, f"stuff_{self._split}.json")

        # Keypoints (auto-detect)
        self._keypoints_json = self._resolve_optional_ann(keypoints_json, f"person_keypoints_{self._split}.json")

        # Captions (auto-detect)
        self._captions_json = self._resolve_optional_ann(captions_json, f"captions_{self._split}.json")

    def _resolve_optional_ann(self, explicit, default_name) -> Optional[Path]:
        if explicit is False:
            return None
        if explicit is not None:
            return Path(explicit)
        candidate = self._ann_dir / default_name
        return candidate if candidate.exists() else None

    @property
    def _has_stuff(self) -> bool:
        return self._stuff_json is not None and self._stuff_json.exists()

    @property
    def _has_keypoints(self) -> bool:
        return self._keypoints_json is not None and self._keypoints_json.exists()

    @property
    def _has_captions(self) -> bool:
        return self._captions_json is not None and self._captions_json.exists()

    def schema(self) -> Dict[str, str]:
        s: Dict[str, str] = {
            "images": "BINARY",
            "mask": "BINARY",
        }
        if self._has_stuff:
            s["stuff/mask"] = "BINARY"
        return s

    def pg_schema(self) -> Dict[str, str]:
        s: Dict[str, str] = {
            "images": "IMAGE",
            "mask": "SEGMENT_MASK",
            "boxes": "BOUNDING_BOX",
        }
        if self._has_stuff:
            s["stuff/mask"] = "SEGMENT_MASK"
            s["stuff/boxes"] = "BOUNDING_BOX"
        if self._has_keypoints:
            s["pose/boxes"] = "BOUNDING_BOX"
        return s

    def image_columns(self) -> List[str]:
        return ["images"]

    def normalize(self) -> Iterator[Dict[str, List[Any]]]:
        if not self.images_dir.is_dir():
            raise FileNotFoundError(f"Images directory not found: {self.images_dir}")
        if not self._instances_json.exists():
            raise FileNotFoundError(f"Instances annotation file not found: {self._instances_json}")

        import numpy as np
        from pycocotools.coco import COCO as _COCOApi

        # --- Load instances ---
        logger.info("Loading instances from %s", self._instances_json)
        coco_inst = _COCOApi(str(self._instances_json))
        with open(self._instances_json) as f:
            instances = _json.load(f)

        cat_info = coco_inst.loadCats(coco_inst.getCatIds())
        cat_names = [c["name"] for c in cat_info]
        super_cat_names = list(set(c["supercategory"] for c in cat_info))
        cat_id_to_idx = {c["id"]: cat_names.index(c["name"]) for c in cat_info}
        cat_id_to_super_idx = {c["id"]: super_cat_names.index(c["supercategory"]) for c in cat_info}

        # --- Load stuff (optional) ---
        coco_stuff = None
        stuff_cat_id_to_idx: Dict[int, int] = {}
        stuff_cat_id_to_super_idx: Dict[int, int] = {}
        has_stuff = self._stuff_json is not None and self._stuff_json.exists()
        if has_stuff:
            logger.info("Loading stuff annotations from %s", self._stuff_json)
            coco_stuff = _COCOApi(str(self._stuff_json))
            stuff_cats = coco_stuff.loadCats(coco_stuff.getCatIds())
            stuff_cat_names = [c["name"] for c in stuff_cats]
            stuff_super_cat_names = list(set(c.get("supercategory", "") for c in stuff_cats))
            stuff_cat_id_to_idx = {c["id"]: stuff_cat_names.index(c["name"]) for c in stuff_cats}
            stuff_cat_id_to_super_idx = {
                c["id"]: stuff_super_cat_names.index(c.get("supercategory", ""))
                for c in stuff_cats
            }

        # --- Load keypoints (optional) ---
        coco_kp = None
        kp_cat_id_to_idx: Dict[int, int] = {}
        kp_cat_id_to_super_idx: Dict[int, int] = {}
        has_keypoints = self._keypoints_json is not None and self._keypoints_json.exists()
        if has_keypoints:
            logger.info("Loading keypoints from %s", self._keypoints_json)
            coco_kp = _COCOApi(str(self._keypoints_json))
            kp_cats = coco_kp.loadCats(coco_kp.getCatIds())
            kp_cat_names = [c["name"] for c in kp_cats]
            kp_super_cat_names = list(set(c["supercategory"] for c in kp_cats))
            kp_cat_id_to_idx = {c["id"]: kp_cat_names.index(c["name"]) for c in kp_cats}
            kp_cat_id_to_super_idx = {
                c["id"]: kp_super_cat_names.index(c["supercategory"])
                for c in kp_cats
            }

        # --- Load captions (optional) ---
        caps_by_image: Dict[int, List[str]] = {}
        if self._captions_json and self._captions_json.exists():
            logger.info("Loading captions from %s", self._captions_json)
            with open(self._captions_json) as f:
                captions_data = _json.load(f)
            for cap in captions_data.get("annotations", []):
                caps_by_image.setdefault(cap["image_id"], []).append(cap["caption"])

        batch: List[Dict[str, Any]] = []
        count = 0

        for img_info in instances.get("images", []):
            if self.max_images is not None and count >= self.max_images:
                break

            image_id = img_info["id"]
            img_path = self.images_dir / img_info["file_name"]
            if not img_path.exists():
                logger.warning("Image not found, skipping: %s", img_path)
                continue

            h = img_info.get("height", 0)
            w = img_info.get("width", 0)

            # --- Instance annotations ---
            inst_anns = coco_inst.loadAnns(coco_inst.getAnnIds(imgIds=image_id))
            combined_mask = np.zeros((max(h, 1), max(w, 1)), dtype=np.uint8)

            boxes_list, cats_list, supercats_list = [], [], []
            areas_list, iscrowds_list, ann_dicts = [], [], []

            for ann in inst_anns:
                cat_id = ann["category_id"]
                if h > 0 and w > 0:
                    m = coco_inst.annToMask(ann)
                    combined_mask[m > 0] = cat_id

                boxes_list.append(ann["bbox"])
                cats_list.append(cat_id_to_idx.get(cat_id, 0))
                supercats_list.append(cat_id_to_super_idx.get(cat_id, 0))
                areas_list.append(ann.get("area", 0))
                iscrowds_list.append(ann.get("iscrowd", 0))
                ann_dicts.append({
                    "id": ann["id"], "bbox": ann["bbox"],
                    "category_id": cat_id, "area": ann.get("area", 0),
                    "iscrowd": ann.get("iscrowd", 0),
                })

            # --- Stuff annotations (optional) ---
            stuff_mask = np.zeros((max(h, 1), max(w, 1)), dtype=np.uint8)
            stuff_boxes_list, stuff_cats_list, stuff_supercats_list = [], [], []
            stuff_areas_list, stuff_iscrowds_list = [], []

            if coco_stuff:
                stuff_anns = coco_stuff.loadAnns(coco_stuff.getAnnIds(imgIds=image_id))
                for ann in stuff_anns:
                    s_cat_id = ann["category_id"]
                    if h > 0 and w > 0:
                        m = coco_stuff.annToMask(ann)
                        stuff_mask[m > 0] = s_cat_id

                    stuff_boxes_list.append(ann.get("bbox", [0, 0, 0, 0]))
                    stuff_cats_list.append(stuff_cat_id_to_idx.get(s_cat_id, 0))
                    stuff_supercats_list.append(stuff_cat_id_to_super_idx.get(s_cat_id, 0))
                    stuff_areas_list.append(ann.get("area", 0))
                    stuff_iscrowds_list.append(ann.get("iscrowd", 0))

            # --- Keypoint / pose annotations (optional) ---
            kp_list = []
            pose_boxes_list, pose_cats_list, pose_supercats_list = [], [], []

            if coco_kp:
                kp_anns = coco_kp.loadAnns(coco_kp.getAnnIds(imgIds=image_id))
                for ann in kp_anns:
                    kp_cat_id = ann["category_id"]
                    pose_cats_list.append(kp_cat_id_to_idx.get(kp_cat_id, 0))
                    pose_supercats_list.append(kp_cat_id_to_super_idx.get(kp_cat_id, 0))
                    pose_boxes_list.append(ann.get("bbox", [0, 0, 0, 0]))
                    if "keypoints" in ann:
                        kp_list.append(ann["keypoints"])

            row: Dict[str, Any] = {
                "images": img_path.read_bytes(),
                "mask": _encode_mask_png(combined_mask),
                "images_meta": _json.dumps(img_info),
                "boxes": [[float(v) for v in box] for box in boxes_list] if boxes_list else None,
                "categories": _json.dumps(cats_list),
                "super_categories": _json.dumps(supercats_list),
                "annotations": _json.dumps(ann_dicts),
                "areas": _json.dumps(areas_list),
                "iscrowds": _json.dumps(iscrowds_list),
                "num_objects": len(inst_anns),
            }

            if caps_by_image:
                row["captions"] = _json.dumps(caps_by_image.get(image_id, []))

            if has_stuff:
                row["stuff/mask"] = _encode_mask_png(stuff_mask)
                row["stuff/boxes"] = [[float(v) for v in box] for box in stuff_boxes_list] if stuff_boxes_list else None
                row["stuff/categories"] = _json.dumps(stuff_cats_list)
                row["stuff/super_categories"] = _json.dumps(stuff_supercats_list)
                row["stuff/areas"] = _json.dumps(stuff_areas_list)
                row["stuff/iscrowds"] = _json.dumps(stuff_iscrowds_list)

            if has_keypoints:
                row["pose/keypoints"] = _json.dumps(kp_list)
                row["pose/boxes"] = [[float(v) for v in box] for box in pose_boxes_list] if pose_boxes_list else None
                row["pose/categories"] = _json.dumps(pose_cats_list)
                row["pose/super_categories"] = _json.dumps(pose_supercats_list)

            batch.append(row)
            count += 1

            if len(batch) >= self.batch_size:
                yield _rows_to_batch(batch)
                batch = []

        if batch:
            yield _rows_to_batch(batch)

        logger.info("COCO normalization complete: %d images processed", count)


def _encode_mask_png(mask) -> bytes:
    from PIL import Image
    buf = io.BytesIO()
    Image.fromarray(mask).save(buf, format="PNG")
    return buf.getvalue()


def _rows_to_batch(rows: List[Dict[str, Any]]) -> Dict[str, List[Any]]:
    all_keys = set()
    for r in rows:
        all_keys.update(r.keys())
    return {k: [r.get(k) for r in rows] for k in all_keys}
